def winner(a: list[int], n: int, k: int) -> int:
    # If k is large enough, the answer is simply n
    if k >= n - 1:
        return n
    best = 0        # Current best element
    times = 0       # Consecutive times `best` has "won"
    for i in range(n):
        if a[i] > best:
            best = a[i]
            if i >= 1:
                times = 1      # Reset times, but count current win
        else:
            times += 1         # Current best wins again
        if times >= k:
            return best
    return best

