def findSubsequenceCount(S: str, T: str) -> int:
    m, n = len(T), len(S)
    # If T is longer than S, T cannot be a subsequence of S
    if m > n:
        return 0
    # DP matrix of size (m + 1) x (n + 1) initialized to 0
    mat = [[0] * (n + 1) for _ in range(m + 1)]
    # An empty string is a subsequence of any prefix of S
    for j in range(n + 1):
        mat[0][j] = 1
    # Fill the DP table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if T[i - 1] != S[j - 1]:
                mat[i][j] = mat[i][j - 1]
            else:
                mat[i][j] = mat[i][j - 1] + mat[i - 1][j - 1]
    return mat[m][n]

