def count_palindromic_substrings(s: str) -> int:
    """
    Python translation of the provided Java method `CountPS`.
    Counts palindromic substrings within the input string `s`.
    """
    n = len(s)
    if n == 0:
        return 0
    # `dp[i][j]` will store the count of palindromic substrings in s[i..j]
    dp = [[0] * n for _ in range(n)]
    # `P[i][j]` will be True if s[i..j] is a palindrome
    P = [[False] * n for _ in range(n)]
    # All length-1 substrings are palindromes
    for i in range(n):
        P[i][i] = True
    # Check for substrings of length 2
    for i in range(n - 1):
        if s[i] == s[i + 1]:
            P[i][i + 1] = True
            dp[i][i + 1] = 1
    # Check for substrings of length ≥ 3
    for gap in range(2, n):
        for i in range(n - gap):
            j = i + gap
            # If the current ends match and the inner substring is a palindrome
            if s[i] == s[j] and P[i + 1][j - 1]:
                P[i][j] = True
            # Update the dp table based on whether s[i..j] itself is a palindrome
            if P[i][j]:
                dp[i][j] = (
                    dp[i][j - 1] + dp[i + 1][j] + 1 - dp[i + 1][j - 1]
                )
            else:
                dp[i][j] = (
                    dp[i][j - 1] + dp[i + 1][j] - dp[i + 1][j - 1]
                )
    return dp[0][n - 1]

