def dealnnoy(n: int, m: int) -> int:
    # Initialize a (m+1) x (n+1) DP table filled with 0
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    # Base cases: first row and first column are all 1
    for i in range(m + 1):
        dp[i][0] = 1
    for j in range(n + 1):
        dp[0][j] = 1
    # Fill the DP table using the given recurrence relation
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            dp[i][j] = dp[i - 1][j] + dp[i - 1][j - 1] + dp[i][j - 1]
