def find_min_insertions(s: str, l: int, h: int) -> int:
    """Return the minimum number of insertions needed to make
    substring s[l..h] a palindrome (inclusive indices)."""
    if l > h:
        return float('inf')                       # Equivalent to Integer.MAX_VALUE
    if l == h:
        return 0
    if l == h - 1:
        return 0 if s[l] == s[h] else 1
    if s[l] == s[h]:
        return find_min_insertions(s, l + 1, h - 1)
