def count_rotations(arr, low, high):
    """
    Determine how many times a sorted array has been rotated.
    :param arr: List[int] - The rotated sorted array
    :param low: int - Starting index for the current search interval
    :param high: int - Ending index for the current search interval
    :return: int - Index of the smallest element (number of rotations)
    """
    if high < low:
        return 0
    if high == low:
        return low
    mid = low + (high - low) // 2
