def even_sum(n: int) -> int:
    """
    Builds Pascal's triangle up to row `n`, then returns the sum of the
    binomial coefficients C(n, k) where k is even.
    """
    # Initialize (n + 1) x (n + 1) table with zeros
    C = [[0] * (n + 1) for _ in range(n + 1)]
    # Fill Pascal's triangle
    for i in range(n + 1):
        for j in range(min(i, n) + 1):
            if j == 0 or j == i:
                C[i][j] = 1
            else:
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j]
