def simplify(expr: str) -> str:
    """
    Direct translation of the provided Java `simplify` routine.
    """
    n = len(expr)
    res = []                 # acts as the Java char[] (but dynamic)
    stack = [0]              # Java’s `Stack<Integer>` – 0: normal, 1: inverted
    i = 0
    while i < n:
        ch = expr[i]
        if ch == '+':
            res.append('-' if stack[-1] == 1 else '+')
        elif ch == '-':
            res.append('+' if stack[-1] == 1 else '-')
        elif ch == '(' and i > 0:
            # manage the sign context, but *do not* append '('
            if expr[i - 1] == '-':
                stack.append(0 if stack[-1] == 1 else 1)
            elif expr[i - 1] == '+':
                stack.append(stack[-1])
        elif ch == ')':
            stack.pop()      # leave out ')' from the result
        else:
            # any other character (including '(' at position 0 or not preceded by + / -)
            res.append(ch)
        i += 1
    return ''.join(res)

