def is_multiple_of_3(n: int) -> int:
    """
    Recursively checks whether an integer is a multiple of 3.
    Returns 1 if true, 0 otherwise (mirrors the Java version).
    """
    odd_count = 0
    even_count = 0
    # Handle negative values
    if n < 0:
        n = -n
    # Base cases
    if n == 0:
        return 1
    if n == 1:
        return 0
    # Count set bits at odd and even positions
    while n != 0:
        if n & 1:
            odd_count += 1
        if n & 2:
            even_count += 1
        n >>= 2  # Shift by 2 to process the next pair of bits
    # Recurse on the absolute difference
    return is_multiple_of_3(abs(odd_count - even_count))

